export const updateChildCardHeights = (
  wrapperRef: React.RefObject<HTMLDivElement>,
  childCardsRef: React.MutableRefObject<HTMLElement[]>,
) => {
  const wrapper = wrapperRef.current;
  const childCards = childCardsRef.current;
  if (wrapper && childCards.length) {
    childCards.forEach((card, idx) => {
      wrapper.style.setProperty(
        `--card-${idx + 1}-height`,
        `${card.scrollHeight}px`,
      );
    });
  }
};
