import {
  useRef,
  Children,
  cloneElement,
  useState,
  useEffect,
  useCallback,
} from 'react';

import { updateChildCardHeights } from './MultiStepCards.helpers';
import { Wrapper } from './MultiStepCards.styles';
import MultiStepCardsProps from './MultiStepCards.types';

const MultiStepCards = ({
  initialStepOverride = 1,
  children,
  className,
}: MultiStepCardsProps) => {
  const [currentStep, setCurrentStep] = useState(initialStepOverride);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const childCardsRef = useRef<HTMLElement[]>([]);
  const handleCurrentStepUpdate = useCallback(
    (targetStep: number) => setCurrentStep(targetStep),
    [],
  );

  useEffect(() => {
    window.addEventListener('resize', () =>
      updateChildCardHeights(wrapperRef, childCardsRef),
    );
    return () => {
      window.removeEventListener('resize', () =>
        updateChildCardHeights(wrapperRef, childCardsRef),
      );
    };
  }, []);

  useEffect(() => {
    window.scrollTo(0, 0);
    updateChildCardHeights(wrapperRef, childCardsRef);
  }, [currentStep]);

  return (
    <Wrapper ref={wrapperRef} className={className}>
      {Children.map(children, (child, index) => {
        const targetStep = index + 1;
        return cloneElement(child, {
          ref: (ref: HTMLElement) => {
            childCardsRef.current[index] = ref;
          },
          totalSteps: children.length,
          currentStep,
          myStep: targetStep,
          myTabIndex: targetStep === currentStep ? 0 : -1,
          isCardActive: currentStep === targetStep,
          handleCurrentStepUpdate,
        });
      })}
    </Wrapper>
  );
};

export default MultiStepCards;
